// Normalisation des données CSV/JSON
const items = $input.all();

// Vérifier que les données existent
if (!items || items.length === 0) {
  return [];
}

const normalizedItems = items.map(item => {
  const raw = item.json;

  // Fonction helper pour récupérer une valeur avec plusieurs clés possibles
  const getValue = (...keys) => {
    for (const key of keys) {
      if (raw[key] !== undefined && raw[key] !== null && raw[key] !== '') {
        return raw[key];
      }
    }
    return null;
  };

  // Normaliser les colonnes avec mapping CSV/JSON
  return {
    json: {
      href: getValue('absolute href', 'href', 'url'),
      titre: getValue('text-headline-1-expanded', 'titre', 'title'),
      marque: getValue('text-body-1 (4)', 'marque', 'brand'),
      prix: getValue('text-headline-2-expanded', 'prix', 'price'),
      date_publication: getValue('text-caption-1 (1)', 'date_publication', 'date'),
      kilometrage: getValue('text-body-1 (5)', 'kilometrage', 'km'),
      annee: getValue('text-body-1 (6)', 'annee', 'year'),
      description: getValue('text-body-1-expanded', 'description', 'desc'),
      localisation: getValue('text-caption-1 (2)', 'localisation', 'location'),
      vendeur: getValue('text-body-1 (7)', 'vendeur', 'seller'),
      // Conserver les données brutes pour debug
      _raw: raw
    }
  };
});

return normalizedItems;

// Filtrer les lignes vides
const items = $input.all();

// Vérifier que les données existent
if (!items || items.length === 0) {
  return [];
}

const filteredItems = items.filter(item => {
  const json = item.json;

  // Vérifier que href et titre existent et ne sont pas vides
  const hasHref = json.href && typeof json.href === 'string' && json.href.trim() !== '';
  const hasTitre = json.titre && typeof json.titre === 'string' && json.titre.trim() !== '';

  if (!hasHref || !hasTitre) {
    return false;
  }

  // Compter les champs non vides (hors _raw)
  const nonEmptyFields = Object.entries(json)
    .filter(([key, value]) => {
      if (key === '_raw') return false;
      return value !== null && value !== undefined && value !== '';
    })
    .length;

  // Garder seulement les lignes avec au moins 3 champs remplis
  return nonEmptyFields >= 3;
});

// Retourner explicitement au format [{json: {...}}]
return filteredItems.map(item => ({
  json: item.json
}));

// Enrichissement avancé avec matching intelligent
const annonces = $input.all();

// Vérifier que les données existent
if (!annonces || annonces.length === 0) {
  return [];
}

// Fonction de normalisation de texte
function normalize(str) {
  if (!str) return '';
  return str.toString().toLowerCase().trim().replace(/\s+/g, ' ');
}

// Fonction pour extraire les modèles de la BDD depuis le flux fusionné
function getBDDModeles() {
  const allModeles = [];

  for (const item of annonces) {
    if (item.json.Marque && item.json.Modèle) {
      allModeles.push({
        Marque: item.json.Marque,
        Modèle: item.json.Modèle,
        'Année début': item.json['Année début'],
        'Année fin': item.json['Année fin'],
        'Cylindrée (cc)': item.json['Cylindrée (cc)'],
        'Type (M/S/E)': item.json['Type (M/S/E)'],
        'Coloris commercial': item.json['Coloris commercial']
      });
    }
  }

  return allModeles;
}

const bddModeles = getBDDModeles();

// Fonction de matching de modèle
function findBestMatch(titre, marque, bdd) {
  const normalizedTitre = normalize(titre);
  const normalizedMarque = normalize(marque);

  if (!normalizedTitre || !normalizedMarque || bdd.length === 0) {
    return null;
  }

  // Filtrer par marque d'abord
  const matchesMarque = bdd.filter(m => 
    normalize(m.Marque) === normalizedMarque
  );

  if (matchesMarque.length === 0) {
    return null;
  }

  // Trouver le meilleur match de modèle
  let bestMatch = null;
  let maxScore = 0;

  for (const model of matchesMarque) {
    const modelName = normalize(model.Modèle);

    if (normalizedTitre.includes(modelName)) {
      const score = modelName.length;

      if (score > maxScore) {
        maxScore = score;
        bestMatch = model;
      }
    }
  }

  return bestMatch;
}

// Enrichir chaque annonce
const enrichedData = annonces.map(annonce => {
  const match = findBestMatch(
    annonce.json.titre,
    annonce.json.marque,
    bddModeles
  );

  // Construire l'objet enrichi
  return {
    json: {
      // Données originales
      href: annonce.json.href,
      titre: annonce.json.titre,
      marque: annonce.json.marque,
      prix: annonce.json.prix,
      date_publication: annonce.json.date_publication,
      kilometrage: annonce.json.kilometrage,
      annee: annonce.json.annee,
      description: annonce.json.description,
      localisation: annonce.json.localisation,
      vendeur: annonce.json.vendeur,

      // Colonnes enrichies
      merge_marque: match?.Marque || annonce.json.marque,
      merge_modele: match?.Modèle || null,
      merge_annees_production: match ? 
        `${match['Année début'] || '?'} → ${match['Année fin'] || '?'}` : 
        null,
      merge_cylindree: match?.['Cylindrée (cc)'] || null,
      merge_type: match?.['Type (M/S/E)'] || null,
      merge_coloris: match?.['Coloris commercial'] || null,

      // Métadonnées de matching
      match_found: !!match,
      match_confidence: match ? 'high' : 'none',
      processed_at: new Date().toISOString()
    }
  };
});

return enrichedData;
